 1	import { type FC, useMemo, useState } from 'react';
 2	import { useForkliftTranslation } from 'src/utils/i18n';
 3	
 4	import type { IoK8sApiCoreV1Secret, V1beta1Provider } from '@kubev2v/types';
 5	import { useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Button, ButtonVariant, Flex, FlexItem } from '@patternfly/react-core';
 7	import { EyeIcon, EyeSlashIcon, PencilAltIcon as Pencil } from '@patternfly/react-icons';
 8	import { getName, getNamespace } from '@utils/crds/common/selectors';
 9	
10	import { getCredentialsViewModeByType } from './utils/getCredentialsViewModeByType';
11	
12	import './CredentialsSectionEditViewModes.style.scss';
13	
14	type CredentialsSectionViewModeProps = {
15	  provider: V1beta1Provider;
16	  secret: IoK8sApiCoreV1Secret;
17	  toggleEdit: () => void;
18	};
19	
20	const CredentialsSectionViewMode: FC<CredentialsSectionViewModeProps> = ({
21	  provider,
22	  secret,
23	  toggleEdit,
24	}) => {
25	  const { t } = useForkliftTranslation();
26	  const [reveal, setReveal] = useState(false);
27	
28	  const [canPatch] = useAccessReview({
29	    group: '',
30	    name: getName(secret),
31	    namespace: getNamespace(secret),
32	    resource: 'secrets',
33	    verb: 'patch',
34	  });
35	
36	  const CredentialsViewModeByType = useMemo(
37	    () => getCredentialsViewModeByType(provider),
38	    [provider],
39	  );
40	
41	  const toggleReveal = () => {
42	    setReveal((isReveal) => !isReveal);
43	  };
44	
45	  return (
46	    <>
47	      <Flex>
48	        {canPatch && (
49	          <FlexItem>
50	            <Button variant={ButtonVariant.secondary} icon={<Pencil />} onClick={toggleEdit}>
51	              {t('Edit credentials')}
52	            </Button>
53	          </FlexItem>
54	        )}
55	        <FlexItem align={{ default: 'alignRight' }}>
56	          <Button
57	            variant={ButtonVariant.link}
58	            icon={reveal ? <EyeSlashIcon /> : <EyeIcon />}
59	            onClick={toggleReveal}
60	          >
61	            {reveal ? t('Hide values') : t('Reveal values')}
62	          </Button>
63	        </FlexItem>
64	      </Flex>
65	
66	      {CredentialsViewModeByType && <CredentialsViewModeByType secret={secret} reveal={reveal} />}
67	    </>
68	  );
69	};
70	
71	export default CredentialsSectionViewMode;

